bool myConstantPropagation(Function &Foo) {
  if (Foo.isDeclaration() || Foo.empty())
    return false;

  bool Changed = false;
  bool LocalChanged;

  do {
    LocalChanged = false;
    for (auto &BB : Foo) {
      for (auto It = BB.begin(), E = BB.end(); It != E;) {
        Instruction *I = &*It++;

        if (!isa<BinaryOperator>(I))
          continue;
        if (!I->getType()->isIntegerTy())
          continue;

        auto *C0 = dyn_cast<ConstantInt>(I->getOperand(0));
        auto *C1 = dyn_cast<ConstantInt>(I->getOperand(1));
        if (!C0 || !C1)
          continue;

        const APInt &V0 = C0->getValue();
        const APInt &V1 = C1->getValue();
        APInt Result;

        switch (I->getOpcode()) {
        case Instruction::Add:
          Result = V0 + V1;
          break;
        case Instruction::Sub:
          Result = V0 - V1;
          break;
        case Instruction::Mul:
          Result = V0 * V1;
          break;
        case Instruction::SDiv:
          if (V1.isZero())
            continue;
          Result = V0.sdiv(V1);
          break;
        case Instruction::UDiv:
          if (V1.isZero())
            continue;
          Result = V0.udiv(V1);
          break;
        case Instruction::Shl:
          Result = V0.shl(static_cast<unsigned>(V1.getZExtValue()));
          break;
        case Instruction::LShr:
          Result = V0.lshr(static_cast<unsigned>(V1.getZExtValue()));
          break;
        case Instruction::AShr:
          Result = V0.ashr(static_cast<unsigned>(V1.getZExtValue()));
          break;
        case Instruction::And:
          Result = V0 & V1;
          break;
        case Instruction::Or:
          Result = V0 | V1;
          break;
        case Instruction::Xor:
          Result = V0 ^ V1;
          break;
        default:
          continue;
        }

        ConstantInt *NewConst = ConstantInt::get(Foo.getContext(), Result);
        I->replaceAllUsesWith(NewConst);
        I->eraseFromParent();
        LocalChanged = true;
      }
    }
    Changed |= LocalChanged;
  } while (LocalChanged);

